import{_ as a,o as e,c as o,ag as r}from"./chunks/framework.BbyMWZAR.js";const g=JSON.parse('{"title":"AI 时代，前端面试应该是什么形式？","description":"","frontmatter":{},"headers":[],"relativePath":"thoughts/ai-era-frontend-interview.md","filePath":"thoughts/ai-era-frontend-interview.md","lastUpdated":1783504823000}'),i={name:"thoughts/ai-era-frontend-interview.md"};function l(n,t,d,h,s,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-时代-前端面试应该是什么形式" tabindex="-1">AI 时代，前端面试应该是什么形式？ <a class="header-anchor" href="#ai-时代-前端面试应该是什么形式" aria-label="Permalink to &quot;AI 时代，前端面试应该是什么形式？&quot;">​</a></h1><blockquote><p>2026-07-08 · 探讨备忘，非标准题库</p></blockquote><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>Copilot、Cursor、Claude 已经深度介入日常开发。候选人可以背八股，AI 也能秒答；Take-home 可以全程代劳；LeetCode 硬刷的边际收益在下降。</p><p>问题变成：<strong>我们还在考什么？考的东西还有没有区分度？</strong></p><p>这篇是对「前端面试形态」的初步思考，和 <code>domains/</code> 里的标准题不同——没有唯一标准答案，欢迎继续推敲。</p><hr><h2 id="ai-让哪些形式失效了" tabindex="-1">AI 让哪些形式失效了 <a class="header-anchor" href="#ai-让哪些形式失效了" aria-label="Permalink to &quot;AI 让哪些形式失效了&quot;">​</a></h2><h3 id="纯背诵型问答" tabindex="-1">纯背诵型问答 <a class="header-anchor" href="#纯背诵型问答" aria-label="Permalink to &quot;纯背诵型问答&quot;">​</a></h3><p>「闭包是什么」「Fiber 是什么」「HTTP 缓存头有哪些」——考的是检索能力，不是工程能力。候选人和 AI 都能答，面试官很难从回答里判断「这个人上线后能不能干活」。</p><h3 id="孤立的手写算法" tabindex="-1">孤立的手写算法 <a class="header-anchor" href="#孤立的手写算法" aria-label="Permalink to &quot;孤立的手写算法&quot;">​</a></h3><p>在空白编辑器里默写 <code>debounce</code>、<code>Promise.all</code>、二叉树遍历，脱离真实上下文时区分度很低。Copilot 能写，刷题也能写；但会不会用、会不会改、会不会 debug，是另一回事。</p><h3 id="无答辩的-take-home" tabindex="-1">无答辩的 Take-home <a class="header-anchor" href="#无答辩的-take-home" aria-label="Permalink to &quot;无答辩的 Take-home&quot;">​</a></h3><p>给三天做一个小项目，交 GitHub 链接——很难区分「本人能力」和「AI + 堆时间」。没有 follow-up 的 homework，价值在快速下降。</p><h3 id="单轮-leetcode-硬刷" tabindex="-1">单轮 LeetCode 硬刷 <a class="header-anchor" href="#单轮-leetcode-硬刷" aria-label="Permalink to &quot;单轮 LeetCode 硬刷&quot;">​</a></h3><p>对前端岗尤其如此。「两数之和」级别的题，AI 和刷题党都能过；业务里的虚拟列表、请求竞态、流式渲染，才是日常痛点，也是更有区分度的考点。</p><hr><h2 id="什么仍然有效-甚至更重要" tabindex="-1">什么仍然有效（甚至更重要） <a class="header-anchor" href="#什么仍然有效-甚至更重要" aria-label="Permalink to &quot;什么仍然有效（甚至更重要）&quot;">​</a></h2><p>AI 时代，面试更应该考 <strong>判断力、协作能力、在约束下交付</strong>，而不是「脑子里有没有标准答案」。</p><table tabindex="0"><thead><tr><th>能力维度</th><th>为什么 AI 替代不了</th></tr></thead><tbody><tr><td>Trade-off 与取舍</td><td>「为什么选 A 不选 B」需要业务上下文、团队约束、历史包袱</td></tr><tr><td>Debug 与定位</td><td>真实 bug 往往跨层（网络 / 渲染 / 状态 / 时序），需要假设、验证、排除</td></tr><tr><td>读代码与 Code Review</td><td>审 AI 生成或同事写的代码，找隐患、提改进，是日常高频动作</td></tr><tr><td>系统设计</td><td>模块边界、数据流、扩展性、降级——没有唯一正确答案</td></tr><tr><td>项目复盘</td><td>失败、延期、方案推翻——考复杂判断，不是背八股</td></tr><tr><td>与 AI 协作</td><td>会 prompt、会验证输出、知道何时不信 AI——已是工程素养</td></tr></tbody></table><p>手册里「散文式答案 + 三个追问」的训练方式，本质上就是在练这种深度：不是背定义，而是被一路追到边界和陷阱。好的面试形态，应该和这种训练方式同构。</p><hr><h2 id="推荐的分层面试形式" tabindex="-1">推荐的分层面试形式 <a class="header-anchor" href="#推荐的分层面试形式" aria-label="Permalink to &quot;推荐的分层面试形式&quot;">​</a></h2><p>比较理想的是 <strong>多轮、多形态组合</strong>，每轮考不同东西，而不是一场两小时 LeetCode + 八股。</p><h3 id="_1-轻量初筛-30–45-min-推理-背诵" tabindex="-1">1. 轻量初筛（30–45 min）：推理 &gt; 背诵 <a class="header-anchor" href="#_1-轻量初筛-30–45-min-推理-背诵" aria-label="Permalink to &quot;1. 轻量初筛（30–45 min）：推理 &gt; 背诵&quot;">​</a></h3><ul><li><strong>形式</strong>：一两道概念题 + 追问，或短代码阅读题</li><li><strong>示例</strong>： <ul><li>「这段 <code>useEffect</code> 为什么死循环？你怎么改？」</li><li>「这个 AI 生成的 SSE 解析缺了什么边界处理？」</li></ul></li><li><strong>要点</strong>：允许查资料、甚至用 AI，但必须边做边讲思路；面试官听的是推理链，不是标准答案</li></ul><h3 id="_2-结对编程-live-coding-60–90-min-真实工作流" tabindex="-1">2. 结对编程 / Live Coding（60–90 min）：真实工作流 <a class="header-anchor" href="#_2-结对编程-live-coding-60–90-min-真实工作流" aria-label="Permalink to &quot;2. 结对编程 / Live Coding（60–90 min）：真实工作流&quot;">​</a></h3><ul><li><strong>形式</strong>：共解一个贴近业务的小题（虚拟列表、请求取消、流式 Markdown 渲染等）</li><li><strong>规则</strong>：<strong>允许用 AI / Copilot</strong>，但要求： <ul><li>解释每一步为什么这样写</li><li>主动验证 AI 输出（跑测试、查边界）</li><li>在 AI 给错时能否发现并纠正</li></ul></li><li><strong>价值</strong>：模拟真实开发，区分「会用 AI」和「被 AI 带着走」</li></ul><h3 id="_3-系统设计-45–60-min-前端架构" tabindex="-1">3. 系统设计（45–60 min）：前端架构 <a class="header-anchor" href="#_3-系统设计-45–60-min-前端架构" aria-label="Permalink to &quot;3. 系统设计（45–60 min）：前端架构&quot;">​</a></h3><ul><li><strong>形式</strong>：白板 / Excalidraw，设计一个具体场景</li><li><strong>示例</strong>： <ul><li>设计一个 ChatGPT 式流式对话 UI（滚动、中断、重试、多轮）</li><li>设计活动配置平台的前端架构（权限、预览、回滚）</li><li>微前端子应用如何隔离样式和路由</li></ul></li><li><strong>追问方向</strong>：性能、错误处理、可观测性、与 AI 能力集成</li></ul><h3 id="_4-项目深挖-45–60-min-证据链" tabindex="-1">4. 项目深挖（45–60 min）：证据链 <a class="header-anchor" href="#_4-项目深挖-45–60-min-证据链" aria-label="Permalink to &quot;4. 项目深挖（45–60 min）：证据链&quot;">​</a></h3><ul><li><strong>形式</strong>：候选人讲一两个核心项目，面试官深挖</li><li><strong>有效追问</strong>： <ul><li>数据口径（「提升 30%」的基线、周期、谁确认）</li><li>技术决策（为什么不用方案 B）</li><li>失败与取舍（延期、回滚、技术债）</li></ul></li><li>高阶面试的区分点，往往在「你有没有真的做过取舍」，而不是「你有没有背过架构名词」</li></ul><h3 id="_5-take-home-答辩-可选" tabindex="-1">5. Take-home + 答辩（可选） <a class="header-anchor" href="#_5-take-home-答辩-可选" aria-label="Permalink to &quot;5. Take-home + 答辩（可选）&quot;">​</a></h3><p>若保留 homework，建议：</p><ul><li>题目小而具体（2–4 小时），带明确约束和测试用例</li><li><strong>必须安排答辩</strong>：讲设计、演示、回答「如果需求变了呢」</li><li>可要求提交 prompt 历史，或 live 时重做一版变体——降低纯 AI 代劳的空间</li></ul><hr><h2 id="ai-时代新增的高频考点" tabindex="-1">AI 时代新增的高频考点 <a class="header-anchor" href="#ai-时代新增的高频考点" aria-label="Permalink to &quot;AI 时代新增的高频考点&quot;">​</a></h2><p>LLM 生态变化快，但有几类前端题已经明显升温，而且 <strong>有代码可写，更考边界和工程化</strong>，比纯八股更有区分度：</p><table tabindex="0"><thead><tr><th>主题</th><th>考什么</th></tr></thead><tbody><tr><td>Streaming UI</td><td>SSE 解析、<code>AbortController</code>、不完整 Markdown 渲染</td></tr><tr><td>Agent / Tool Calling</td><td>多轮 tool loop、并行 tool、错误反馈</td></tr><tr><td>RAG 前端</td><td>检索结果展示、引用溯源、loading 状态</td></tr><tr><td>Prompt / Token</td><td>前端为什么要关心 token 预算、截断策略</td></tr><tr><td>Eval &amp; Safety</td><td>幻觉展示、成本管控、prompt injection 防护</td></tr></tbody></table><p>这类题的共同特点：<strong>第一性原理 + 边界 case</strong>，比背某个 SDK 的 API 更耐过时。出题和备考都应偏向「理解协议与约束」，而非「记住某版本语法」。</p><hr><h2 id="对备考和出题的启示" tabindex="-1">对备考和出题的启示 <a class="header-anchor" href="#对备考和出题的启示" aria-label="Permalink to &quot;对备考和出题的启示&quot;">​</a></h2><h3 id="候选人" tabindex="-1">候选人 <a class="header-anchor" href="#候选人" aria-label="Permalink to &quot;候选人&quot;">​</a></h3><ul><li>少花时间背标准答案，多练 <strong>讲清楚 why + 被追问三层</strong></li><li>手写的价值在于理解原理，以便 debug 和 review，不是为了默写</li><li>准备两三个 <strong>有数据、有取舍、有失败</strong> 的项目故事</li><li>学会在 AI 辅助下高效解题，并主动暴露验证过程</li></ul><h3 id="面试官-出题人" tabindex="-1">面试官 / 出题人 <a class="header-anchor" href="#面试官-出题人" aria-label="Permalink to &quot;面试官 / 出题人&quot;">​</a></h3><ul><li>题面设计成开放 + 可追问，而不是封闭式填空</li><li>手写题优先选 <strong>有业务上下文、有边界 case</strong> 的</li><li>明确是否允许 AI；若允许，考核标准要改成 <strong>过程与判断</strong>，不是代码行数</li><li>定期更新题库（尤其 AI 相关），标注验证时间——生态变得快，过时题会误导</li></ul><h3 id="对本手册" tabindex="-1">对本手册 <a class="header-anchor" href="#对本手册" aria-label="Permalink to &quot;对本手册&quot;">​</a></h3><p><code>domains/</code> 的形态已经比较贴近「好面试」的训练方式：散文式答案练表达，追问模拟深挖，playground 验证理解。<code>thoughts/</code> 则放这种 meta 探讨——不强行变成标准题，但可以为后续出题方向提供输入。</p><hr><h2 id="一句话收束" tabindex="-1">一句话收束 <a class="header-anchor" href="#一句话收束" aria-label="Permalink to &quot;一句话收束&quot;">​</a></h2><blockquote><p>AI 时代的前端面试，应从「考你知道多少」转向「考你怎么想、怎么协作、怎么在真实约束下交付」。</p></blockquote><p>理想形态是：<strong>轻量推理初筛 + 允许 AI 的结对编程 + 系统设计 + 项目深挖</strong>。手写和八股保留为「理解深度的探针」，而不是主菜。</p><hr><h2 id="待继续想的问题" tabindex="-1">待继续想的问题 <a class="header-anchor" href="#待继续想的问题" aria-label="Permalink to &quot;待继续想的问题&quot;">​</a></h2><ul><li>不同级别（ junior / senior / lead）的权重应该怎么分？</li><li>「允许 AI」的面试，评分 rubric 怎么写才公平、可复现？</li><li>线上异步面试（录屏 + 答辩）和 onsite 结对，信噪比差多少？</li><li>团队已经在日常用 AI 开发，面试还考「不许用 AI 的手写」，是不是在考假技能？</li></ul>',55)])])}const m=a(i,[["render",l]]);export{g as __pageData,m as default};
